   350→// parseRequest parses a request into parsed queries grouped by datasource uid
   351→func (s *ServiceImpl) parseMetricRequest(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest, supportLocalTimeRange bool) (*parsedRequest, error) {
   352→	if len(reqDTO.Queries) == 0 {
   353→		return nil, ErrNoQueriesFound
   354→	}
   355→
   356→	req := &parsedRequest{
   357→		hasExpression: false,
   358→		parsedQueries: make(map[string][]parsedQuery),
   359→		dsTypes:       make(map[string]bool),
   360→	}
   361→
   362→	// Parse the queries and store them by datasource
   363→	datasourcesByUid := map[string]*datasources.DataSource{}
   364→	for _, query := range reqDTO.Queries {
   365→		ds, err := s.getDataSourceFromQuery(ctx, user, skipDSCache, query, datasourcesByUid)
   366→		if err != nil {
   367→			return nil, err
   368→		}
   369→		if ds == nil {
   370→			return nil, ErrInvalidDatasourceID
   371→		}
   372→
   373→		datasourcesByUid[ds.UID] = ds
   374→		if expr.NodeTypeFromDatasourceUID(ds.UID) != expr.TypeDatasourceNode {
   375→			req.hasExpression = true
   376→		} else {
   377→			req.dsTypes[ds.Type] = true
   378→		}
   379→
   380→		if _, ok := req.parsedQueries[ds.UID]; !ok {
   381→			req.parsedQueries[ds.UID] = []parsedQuery{}
