   114→// called by mt query service and also when queryServiceFromUI is enabled, can be both mt and st
   115→func (r *queryREST) Connect(connectCtx context.Context, name string, _ runtime.Object, incomingResponder rest.Responder) (http.Handler, error) {
   116→	// See: /pkg/services/apiserver/builder/helper.go#L34
   117→	// The name is set with a rewriter hack
   118→	if name != "name" {
   119→		r.logger.Debug("Connect name is not name")
   120→		return nil, errorsK8s.NewNotFound(schema.GroupResource{}, name)
   121→	}
   122→	b := r.builder
   123→
   124→	return http.HandlerFunc(func(w http.ResponseWriter, httpreq *http.Request) {
   125→		ctx, span := b.tracer.Start(httpreq.Context(), "QueryService.Query")
   126→		defer span.End()
   127→		ctx = request.WithNamespace(ctx, request.NamespaceValue(connectCtx))
   128→		traceId := span.SpanContext().TraceID()
   129→		connectLogger := b.log.New("traceId", traceId.String(), "rule_uid", httpreq.Header.Get("X-Rule-Uid"))
   130→		responder := newResponderWrapper(incomingResponder,
   131→			func(statusCode *int, obj runtime.Object) {
   132→				if *statusCode/100 == 4 {
   133→					span.SetStatus(codes.Error, strconv.Itoa(*statusCode))
   134→				}
   135→
   136→				if *statusCode >= 500 {
   137→					o, ok := obj.(*query.QueryDataResponse)
   138→					if ok && o.Responses != nil {
   139→						for refId, response := range o.Responses {
   140→							if response.ErrorSource == backend.ErrorSourceDownstream {
   141→								*statusCode = http.StatusBadRequest //force this to be a 400 since it's downstream
   142→								span.SetStatus(codes.Error, strconv.Itoa(*statusCode))
   143→								span.SetAttributes(attribute.String("error.source", "downstream"))
   144→								break
   145→							} else if response.Error != nil {
   146→								connectLogger.Debug("500 error without downstream error source", "error", response.Error, "errorSource", response.ErrorSource, "refId", refId)
   147→								span.SetStatus(codes.Error, "500 error without downstream error source")
   148→							} else {
   149→								span.SetStatus(codes.Error, "500 error without downstream error source and no Error message")
   150→								span.SetAttributes(attribute.String("error.ref_id", refId))
   151→							}
   152→						}
   153→					}
   154→				}
   155→				connectLogger.Debug("responder sending status code", "statusCode", statusCode)
   156→			},
   157→
   158→			func(err error) {
   159→				connectLogger.Error("error caught in handler", "err", err)
   160→				span.SetStatus(codes.Error, "query error")
   161→
   162→				if err == nil {
   163→					return
   164→				}
   165→
   166→				span.RecordError(err)
   167→			})
   168→
   169→		raw := &query.QueryDataRequest{}
   170→		err := web.Bind(httpreq, raw)
   171→		if err != nil {
   172→			connectLogger.Error("Hit unexpected error when reading query", "err", err)
   173→			err = errorsK8s.NewBadRequest("error reading query")
   174→			// TODO: can we wrap the error so details are not lost?!
   175→			// errutil.BadRequest(
   176→			// 	"query.bind",
   177→			// 	errutil.WithPublicMessage("Error reading query")).
   178→			// 	Errorf("error reading: %w", err)
   179→			responder.Error(err)
   180→			return
   181→		}
   182→
   183→		qdr, err := handleQuery(ctx, *raw, *b, httpreq, *responder, connectLogger)
   184→
   185→		if err != nil {
   186→			connectLogger.Error("execute error", "http code", query.GetResponseCode(qdr), "err", err)
   187→			logEmptyRefids(raw.Queries, connectLogger)
   188→			if qdr != nil { // if we have a response, we assume the err is set in the response
   189→				responder.Object(query.GetResponseCode(qdr), &query.QueryDataResponse{
   190→					QueryDataResponse: *qdr,
   191→				})
   192→				return
   193→			} else {
   194→				var errorDataResponse backend.DataResponse
   195→
   196→				badRequestErrors := []error{
   197→					service.ErrInvalidDatasourceID,
   198→					service.ErrNoQueriesFound,
   199→					service.ErrMissingDataSourceInfo,
   200→					service.ErrQueryParamMismatch,
   201→					service.ErrDuplicateRefId,
   202→					datasources.ErrDataSourceNotFound,
   203→				}
   204→				isTypedBadRequestError := false
   205→				for _, badRequestError := range badRequestErrors {
   206→					if errors.Is(err, badRequestError) {
   207→						isTypedBadRequestError = true
   208→					}
   209→				}
   210→				if isTypedBadRequestError {
   211→					errorDataResponse = backend.ErrDataResponseWithSource(backend.StatusBadRequest, backend.ErrorSourceDownstream, err.Error())
   212→				} else if strings.Contains(err.Error(), "expression request error") {
   213→					connectLogger.Error("Error calling TransformData in an expression", "err", err)
   214→					errorDataResponse = backend.ErrDataResponseWithSource(backend.StatusBadRequest, backend.ErrorSourceDownstream, err.Error())
   215→				} else {
   216→					connectLogger.Error("unknown error, treated as a 500", "err", err)
   217→					responder.Error(err)
   218→					return
   219→				}
   220→				// TODO ensure errors also return the refId wherever possible
   221→				errorRefId := raw.Queries[0].RefID
   222→				if errorRefId == "" {
   223→					errorRefId = "A"
   224→				}
   225→
   226→				qdr = &backend.QueryDataResponse{
   227→					Responses: map[string]backend.DataResponse{
   228→						errorRefId: errorDataResponse,
   229→					},
   230→				}
   231→				responder.Object(query.GetResponseCode(qdr), &query.QueryDataResponse{
   232→					QueryDataResponse: *qdr,
   233→				})
   234→				return
   235→			}
   236→		}
   237→
   238→		responder.Object(query.GetResponseCode(qdr), &query.QueryDataResponse{
   239→			QueryDataResponse: *qdr, // wrap the backend response as a QueryDataResponse
   240→		})
   241→	}), nil
   242→}
