   326→type responderWrapper struct {
   327→	wrapped    rest.Responder
   328→	onObjectFn func(statusCode *int, obj runtime.Object)
   329→	onErrorFn  func(err error)
   330→}
   331→
   332→func newResponderWrapper(responder rest.Responder, onObjectFn func(statusCode *int, obj runtime.Object), onErrorFn func(err error)) *responderWrapper {
   333→	return &responderWrapper{
   334→		wrapped:    responder,
   335→		onObjectFn: onObjectFn,
   336→		onErrorFn:  onErrorFn,
   337→	}
   338→}
   339→
   340→func (r responderWrapper) Object(statusCode int, obj runtime.Object) {
   341→	if r.onObjectFn != nil {
   342→		r.onObjectFn(&statusCode, obj)
   343→	}
   344→
   345→	r.wrapped.Object(statusCode, obj)
   346→}
   347→
   348→func (r responderWrapper) Error(err error) {
   349→	if r.onErrorFn != nil {
   350→		r.onErrorFn(err)
   351→	}
   352→
   353→	r.wrapped.Error(err)
   354→}
